// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- QUOTE: empty and base premiums ---
  it.todo("empty item list yields premium of 5G (processing fee only)");
  it.todo("quote for a single sword yields 105G (100G base + 5G fee)");
  it.todo("quote for a single amulet yields 65G (60G base + 5G fee)");
  it.todo("quote for a single staff yields 85G (80G base + 5G fee)");
  it.todo("quote for a single potion yields 45G (40G base + 5G fee)");

  // --- QUOTE: components and blocks ---
  it.todo("quote for a single rune yields 30G (25G base + 5G fee)");
  it.todo("quote for 2 runes yields 55G (50G base + 5G fee)");
  it.todo("quote for 3 runes applies block: 65G (60G base + 5G fee)");
  it.todo("quote for 4 runes does not apply block: 105G (100G base + 5G fee)");
  it.todo("quote for 7 runes yields 180G (175G base = block of 3 + 4 separate, 60+25+25+25+25 = wait, 60+4*25=160? re-check: spec says 7 runes -> 175G base)");
  it.todo("quote for 2 runes + 1 moonstone yields 80G base premium (75G base + 5G fee = 80G; no block — different types)");
  it.todo("quote for 3 runes + 3 moonstones applies two separate blocks: 125G (120G base + 5G fee)");

  // --- QUOTE: item-specific modifiers ---
  it.todo("cursed sword adds 50% surcharge to that item's base premium");
  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 stacks both surcharges");

  // --- QUOTE: policy-wide modifiers ---
  it.todo("first insurance adds 10% surcharge per item to policy base premium");
  it.todo("long-standing customer (2 years) gets 20% loyalty discount on policy base premium");
  it.todo("customer with exactly 2 years receives loyalty discount (threshold)");
  it.todo("customer with less than 2 years does not receive loyalty discount");
  it.todo("follow-up contract (second quote) gets 15% discount");

  // --- QUOTE: integration examples from spec ---
  it.todo("newcomer with cursed sword (steel, enchantment 3) -> premium 165G");
  it.todo("multi-item: cursed sword + plain amulet -> 210G before policy modifiers and fee");
  it.todo("long-standing customer's second contract: cursed sword (enchantment 7) -> 160G");

  // --- QUOTE: rounding ---
  it.todo("premium of 197.5G rounds up to 198G (in MHPCO's favor)");

  // --- QUOTE: rejections ---
  it.todo("quote with unknown item type causes CLI to exit non-zero with no results on stdout");

  // --- CLAIM: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500G -> payout 400G");
  it.todo("damage to a rune (insurance 250G), damage 200G -> payout 100G");

  // --- CLAIM: deductible per damage event ---
  it.todo("dragon attack damages sword (500G) and amulet (300G) -> payout 600G (deductible per item)");

  // --- CLAIM: enchantment threshold ---
  it.todo("steel sword, enchantment 9, damage 1000G -> payout 400G (50% then deductible)");

  // --- CLAIM: dragon material ---
  it.todo("dragon-material sword, enchantment 5, damage 800G -> payout 700G (full reimbursement, deductible)");
  it.todo("dragon-material sword with enchantment 8 + 1000G damage -> payout 400G (high-ench applies, deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000G -> payout 400G (50% rule wins, then deductible)");

  // --- CLAIM: rounding ---
  it.todo("payout calculation of 350.5G rounds down to 350G");

  // --- CLAIM: cap and multiple items ---
  it.todo("policy with two swords -> insurance sum 2000G, cap 4000G");
  it.todo("two sword damages on a two-sword policy -> each entry has its own deductible");
  it.todo("cursed sword has cap 2000G (based on unmodified insurance value, not modified premium)");
  it.todo("policy with sword + 3 runes -> insurance sum 1750G (block discount affects only premium)");

  // --- CLAIM: cap exhaustion across successive claims ---
  it.todo("sword (cap 2000G), first claim 1500G -> payout 1400G, remaining cap 600G");
  it.todo("sword (cap 2000G), second claim 1500G after first -> payout 600G, remaining cap 0G");

  // --- CLAIM: rejections ---
  it.todo("claim references item not in policy -> CLI exits non-zero");
  it.todo("claim contains damage entry with negative amount -> CLI exits non-zero");
  it.todo("more damage entries of a type than policy covers -> CLI exits non-zero, whole claim rejected");
});
